    q = "WITH mx AS (" + " UNION ALL ".join(one_select(sym) for sym in ch) + ") SELECT * FROM mx WHERE max_adj_close > 200"
    queries.append(q)

print('__RESULT__:')
print(json.dumps({'queries': queries, 'n_chunks': len(queries)}))"}

